func TestMaybeAttachInspectRepoFingerprintHint(t *testing.T) {
	req := types.SubmitJobRequest{
		TaskType: "inspect_repo",
		InputRefs: []types.InputRef{
			{Type: "repo", URI: "file:///tmp/repo"},
		},
		TaskParams: map[string]any{
			"query": "trace broker timeout",
			"mode":  "answer",
		},
	}

	maybeAttachInspectRepoFingerprintHint(&req, "git:abc123")

	if got := stringValue(req.TaskParams["_broker_repository_state_fingerprint"]); got != "git:abc123" {
		t.Fatalf("expected broker fingerprint hint to be attached, got %q", got)
	}
	if got := stringValue(req.TaskParams["_broker_repository_state_fingerprint_source"]); got != "request_cache" {
		t.Fatalf("expected broker fingerprint source to be attached, got %q", got)
	}
}

func TestMaybeAttachInspectRepoFingerprintHintSkipsExcludedRequests(t *testing.T) {
	req := types.SubmitJobRequest{
		TaskType: "inspect_repo",
		InputRefs: []types.InputRef{
			{Type: "repo", URI: "file:///tmp/repo"},
		},
		TaskParams: map[string]any{
			"query":              "trace broker timeout",
			"excluded_dir_names": []string{"vendor"},
		},
	}

	maybeAttachInspectRepoFingerprintHint(&req, "git:abc123")

	if got := stringValue(req.TaskParams["_broker_repository_state_fingerprint"]); got != "" {
		t.Fatalf("expected broker fingerprint hint to be omitted for excluded requests, got %q", got)
	}
}
